695c9ecad574119fd5c0c10a.sql:
select studentid , concat(firstname , ' ' , lastname) as fullname , courseid , enrollmentdate
from students join enrollments
using (studentid)
where datediff(curdate() , enrollmentdate) / 7 <= 11 ;

695c9ecad574119fd5c0c10e.sql:
select coursename , concat(lecturers.firstname , ' ' , lecturers.lastname) as fullname , seniority , credits
from courses join lecturers
using (courseid)
where seniority >= 7
and department = 'מדעי המחשב'
order by credits asc ;

695c9ecad574119fd5c0c110.sql:
select department, grade
from courses join enrollments 
using (courseid)
order by grade desc
limit 1 ;

695c9ecad574119fd5c0c112.sql:
select department , count(distinct lecturerid)
from courses join lecturers
using (courseid)
where seniority > 12
group by department
having count(distinct lecturerid) >= 3;

695c9ecad574119fd5c0c114.sql:
select courses.courseid , coursename , count(*) as numofstudents , count(*) / (select count(*) from enrollments where year(enrollmentdate) >= 2023) * 100 as perofstudents
from courses join enrollments
using (courseid)
where year(enrollmentdate) >= 2023
group by courses.courseid , coursename;

695c9ecbd574119fd5c0c11a.sql:
select concat(firstname , ' ' , lastname) as fullname , coursename
from lecturers left outer join courses
using (courseid)
order by firstname asc ;

695c9ecbd574119fd5c0c11e.sql:
select students.studentid , concat(students.firstname , ' ' ,students.lastname) as studentname, students.city , coursename , concat(lecturers.firstname , ' ' ,lecturers.lastname) as lecturername
from students join enrollments
using (studentid) 
join courses
using (courseid)
join lecturers using (courseid)
where students.city = lecturers.city;

695c9ecbd574119fd5c0c120.sql:
select students.studentid , concat(students.firstname , ' ' , students.lastname) as fullname , avg(grade)
from students join enrollments
using (studentid) join courses using(courseid)
where department = 'מדעי המחשב'
group by students.studentid , students.firstname , students.lastname 
having avg(grade) >=(select avg(grade)
 from enrollments join courses 
 using (courseid)
 where department = 'מדעי המחשב') ;

695c9ecbd574119fd5c0c122.sql:
select enrollments.courseid , coursename, avg(grade) , count(*)  as numofstudents
from courses join enrollments
using (courseid)
group by enrollments.courseid , coursename
order by avg(grade) desc
limit 3 ;

695c9ecbd574119fd5c0c11c.sql:
select enrollments.studentid, coursename , grade as prev_grade , grade + 6 as new_grade  
from enrollments join courses 
using(courseid)
where coursename = 'Calculus I' 
and grade < 70 ;

/*UPDATE Enrollments e join Coursesc 
USING (CourseID)
SET e.Grade = e.Grade + 6
    WHERE c.CourseName = 'Calculus I' and e.Grade<70
  );*/


SELECT e.StudentID,c.CourseName,e.Grade - 6 AS old_grade,e.Grade AS new_grade
FROM Enrollments e JOIN Courses c 
USING (CourseID)
WHERE c.CourseName = 'Calculus I' AND (e.Grade-6) < 70;

695c9ecad574119fd5c0c10a.sql:
select StudentID,concat(FirstName,' ',LastName)as fullName,
CourseID,EnrollmentDate
from Enrollments join Students
using(StudentID)
where datediff(curdate(),EnrollmentDate) between 0 and 77;

695c9ecad574119fd5c0c110.sql:
select Department
from Courses as C join Enrollments as E
using(CourseID)
where Grade in
(select max(Grade)
from Enrollments);

695c9ecad574119fd5c0c112.sql:
select Department,count(distinct(LecturerID))
from Courses join Lecturers
using (CourseID)
where Seniority>12
group by Department
having count(distinct(LecturerID))>=3;

695c9ecbd574119fd5c0c118.sql:
select StudentID,Grade*1.1 as updateGrade,Department
from Courses join Enrollments
using (CourseID)
where StudentID in(select StudentID 
from Courses join Enrollments 
using (CourseID) 
where CourseName='Calculus I')
and CourseName='Introduction to CS'
and Department='Computer Science'
order by Grade*1.1 desc, Department asc;

695c9ecbd574119fd5c0c11a.sql:
select concat(FirstName,' ',LastName)as fullName, CourseName
from Lecturers left outer join  Courses
using (CourseID)
order by fullName ASC;

695c9ecbd574119fd5c0c11c.sql:
select StudentID,CourseName,Grade,Grade+6 as NEWgrade
from Courses join Enrollments
using(CourseID)
where CourseName='Calculus I' and Grade<70;
