אם כן, פשוט הייתי מוסיף יוניון*/

695c9ecad574119fd5c0c10a.sql:
select StudentID, concat(FirstName,' ',LastName) as FullName, CourseID, EnrollmentDate
from Students join Enrollments using (StudentID)
where DATEDIFF(CURDATE(), EnrollmentDate) BETWEEN 0 AND 77;

695c9ecad574119fd5c0c10c.sql:
select StudentId, concat(Firstame, ' ', LastName) as FullName, avg(grade) as AvgGrade
from Students join Enrollments using(StudentId)
group by Enrollments.StudentId, Firstame, LastName
having AvgGrade> all(select avg(grade) from Enrollments group by StudentId);

695c9ecad574119fd5c0c10e.sql:
select CourseName, concat(L.FirstName, ' ',L.LastName) as LucturerFullName, L.Seniority, Credits
from Courses as C join Lecturers as L using(courseid)
where Department = 'Computer Science' and Seniority>= 7 
order by Credits asc;

695c9ecad574119fd5c0c110.sql:
select distinct Department 
from Courses join Enrollments using(CourseID)
where grade>= all(select grade from Enrollments);

695c9ecad574119fd5c0c112.sql:
select Department ,count(distinct LecturerID) as NumOfLucterers 
from Courses join Lecturers using (CourseId)
where Seniority > 12
group by Department
having count(distinct LecturerID) >=3;

695c9ecad574119fd5c0c114.sql:
select c.CourseId, c.CourseName, count(distinct e.StudentId) as NumOfStudents, count(distinct e.StudentId) * 100 / (select count(*) from students) as prcentage 
from Courses as c join Enrollments as e using(CourseID)
where e.EnrollmentDate >= '2023-01-01'
group by c.CourseId, c.CourseName;

695c9ecbd574119fd5c0c11a.sql:
select concat(FirstName, ' ',LastName) as LecturerName, CourseName 
from Lecturers left outer join Courses using(CourseId)
order by LecturerName;

695c9ecbd574119fd5c0c11e.sql:
select S.StudentID, concat(S.FirstName, ' ',S.LastName) as StudentFullName, S.city, C.CourseName, concat(L.FirstName, ' ',L.LastName) as LecturerFullName
from Students as S join Enrollments as E using(StudentID) join Courses as C using(CourseID) join Lecturers as L using(CourseID)
where S.city = L.city;

695c9ecbd574119fd5c0c120.sql:
select S.StudentID, concat(S.FirstName, ' ', S.LastName) as StudentFullName, avg(E.Grade) as AvgGrade
from Students as S join Enrollments as E using(StudentID) join Courses as C using(CourseID)
where C.Department = 'Computer Sceince' 
group by S.StudentID, S.FirstName, S.LastName 
Having avg(E.Grade) > (select avg(Enrollments.Grade) from Enrollments Join Courses using(CourseID) where Courses.Department = 'Computer Sceince');

695c9ecbd574119fd5c0c122.sql:
select C.CourseID, C.CourseName, avg(E.Grade) as AvgGrade, count(distinct E.StudentID) as NumOfStudents 
from Courses as C join Enrollments as E using(CourseID)
group by C.CourseID, C.CourseName
order by AvgGrade desc
limit 3;

695c9ecbd574119fd5c0c118.sql:
select S.StudentID, E.Grade * 1.1 as NewGrade, C.Department
from Students as S join Enrollments as E using(StudentID) join Courses as C using(CourseID)
where C.CourseName = 'Intoduction to CS' and C.Department = 'Computer Science' and S.studentID in(select Enrollments.StudentID from Enrollments join Courses using(CourseID) where CourseName = 'Calculus I' and Department = 'Computer Science')
order by NewGrade desc, C.Department asc;

695c9ecbd574119fd5c0c11c.sql:
select StudentID, CourseName, Grade as OldGrade, Grade+6 as NewGrade 
from Enrollments join Courses using(CourseID)
where CourseName = 'Calculus I' and Grade< 70;

695c9ecad574119fd5c0c10a.sql:
select S.StudentID, CONCAT(S.FirstName,' ',S.LastName) AS FULLNAME, E.CourseID, E.EnrollmentDate
from Students S join Enrollments E using(StudentID)
where DATEDIFF('2026-01-13', E.EnrollmentDate) <= 11 * 7

695c9ecad574119fd5c0c110.sql:
SELECT C.Department
FROM Courses C JOIN Enrollments E using(CourseID)
WHERE E.Grade = (SELECT MAX(Grade) FROM Enrollments);

695c9ecbd574119fd5c0c11a.sql:
SELECT CONCAT(L.FirstName, ' ', L.LastName) AS LecturerName, C.CourseName
FROM Lecturers L LEFT JOIN Courses C ON L.CourseID = C.CourseID
ORDER BY LecturerName ASC;

695c9ecbd574119fd5c0c11e.sql:
SELECT S.StudentID, CONCAT(S.FirstName, ' ', S.LastName) AS StudentName, C.CourseName, CONCAT(L.FirstName, ' ', L.LastName) AS LecturerName
FROM Students S JOIN Enrollments E USING (StudentID) JOIN Courses C USING (CourseID) JOIN Lecturers L USING (CourseID)
WHERE S.City = L.City;

695c9ecad574119fd5c0c10a.sql:
select StudentID, concat(FirstName,"", LastName),CourseID,EnrollmentDate
from Students join Enrollments using (StudentID)
where DATEDIFF('2026-01-13',EnrollmentDate)<=77

695c9ecad574119fd5c0c110.sql:
select Department
from Courses join Enrollments using(CourseID)
 where Grade=(SELECT max (Grade) FROM Enrollments)

695c9ecbd574119fd5c0c11e.sql:
select StudentID,FirstName,CourseName,City
from Students join Enrollments using (StudentID) join Courses using (CourseID)
where (city in (select city from Lecturers)) and (CourseID in (select CourseID  from Lecturers));

695c9ecbd574119fd5c0c11a.sql:
select concat (lecturers.firstname," ",lecturers.lastname)
as fullname,coursename
from lecturers left outer join courses using(courseID)

695c9ecad574119fd5c0c10c.sql:
select s.StudentID , s.FirstName, avg(e.Grade)
from Students s join Enrollments e using(StudentID)
group by s.StudentID , s.FirstName
HAVING avg(e.Grade) >= (
       select max (avg_grade)
       from (
         select avg(Grade) as avg_grade
         from Enrollments
         Group by StudentID
       ) t
);

695c9ecad574119fd5c0c10e.sql:
select c.CourseName, l.FirstName , l.Seniority , c.Credits
from Courses c join Lecturers l using(CourseID)
where c.Department = 'Computer Science' and l.Seniority >= 7 
ORDER BY c.Credits ;

695c9ecad574119fd5c0c110.sql:
select distinct c.Department
from Courses c join Enrollments e using (CourseID)
where e.Grade = (
       select max(Grade)
       from Enrollments
) ;

695c9ecad574119fd5c0c114.sql:
select c.CourseID, c.CourseName, count(DISTINCT e.StudentID),
count(DISTINCT e.StudentID) *100.0 / (SELECT count(DISTINCT StudentID) 
        from Enrollments )
from Courses c join Enrollments e using (CourseID)
WHERE year(e.EnrollmentDate) >= 2023
group by c.CourseID, c.CourseName ;

695c9ecbd574119fd5c0c11a.sql:
SELECT l.FirstName , c.CourseName
from Lecturers l left join Courses c on l.CourseID=c.CourseID
Order by l.FirstName ;

695c9ecbd574119fd5c0c11e.sql:
select s.StudentID, s.FirstName, s.City, c.CourseName, l.FirstName
from Enrollments e join Students s using (StudentID)
JOIN Lecturers l using(CourseID)
join Courses c using(CourseID)
where s.City= l.City ;

695c9ecbd574119fd5c0c120.sql:
SELECT s.StudentID , s.FirstName, AVG(e.Grade) as avgGrade
from Enrollments e join Courses c using (CourseID)
JOIN Students s using(StudentID)
where c.Department= 'Computer Science'
Group by s.StudentID , s.FirstName
having avg(e.Grade) > (
       select avg(E.Grade)
       from Enrollments E join Courses C using(CourseID)
       where C.Department= 'Computer Science'
 );

695c9ecbd574119fd5c0c122.sql:
select c.CourseID, c.CourseName , avg(e.Grade) as AVGRADE, count(e.StudentID)
from Enrollments e join Courses c using(CourseID)
group by  c.CourseID , c.CourseName
order by AVGRADE desc
limit 3 ;

695c9ecad574119fd5c0c10e.sql:
select CourseName,concat(FirstName,' ',LastName),Seniority,Credits
from Courses left outer join Lecturers
using (CourseID)
where Seniority>=7 and Department="Computer Science"
order by Credits asc;

695c9ecad574119fd5c0c110.sql:
select Department 
from Courses left outer join Enrollments
using (CourseID)
where Grade=(select max(Grade)from Enrollments);

695c9ecad574119fd5c0c112.sql:
select Department,count(*) num_Lecturers
from Courses inner join Lecturers
using (CourseID)
where Seniority>12
group by Department
having count(distinct(LecturerID))>=3;

695c9ecbd574119fd5c0c11a.sql:
select concat(FirstName,' ',LastName)as Full_Name,CourseName
from Courses left outer join  Lecturers
using (CourseID)
union 
select concat(FirstName,' ',LastName)as Full_Name,CourseName
from Lecturers left outer join Courses
using (CourseID)
where Courses.CourseID is null
order by Full_Name ;

695c9ecad574119fd5c0c10a.sql:
select Students.StudentId, CONCAT(FirstName," ",LastName) as fullName, CourseID, EnrollmentDate
from Students join Enrollments
using(StudentId)
where DATEDIFF("2025-01-13",Enrollments.EnrollmentDate) <11*7;

695c9ecad574119fd5c0c10c.sql:
select Students.StudentID, CONCAT(FirstName," ",LastName) as fullName, avg(Grade)
from Students join Enrollments
using(StudentID)
group by Students.StudentID, CONCAT(FirstName," ",LastName)
having avg(Grade) = (select max(average) from (select avg(Grade) as average from Enrollments group by StudentID));

695c9ecad574119fd5c0c10e.sql:
select CourseName, CONCAT(FirstName," ",LastName) as fullName,Seniority,Credits
from Courses join Lecturers
using(CourseID)
where Department="Computer Science" and Seniority>=7
order by Credits;

695c9ecad574119fd5c0c110.sql:
select Department
from Courses join Enrollments
using(CourseID)
where Grade = (select max(Grade) from Enrollments);

695c9ecad574119fd5c0c112.sql:
select Department, count(*)
from Courses join Lecturers
using(CourseID)
where Seniority>12
group by Department
having count(DISTINCT LecturerID)>=3;

695c9ecad574119fd5c0c114.sql:
select Courses.CourseID,CourseName,count(*) as numOfEnrollment, count(*)/(select count(*) from Enrollments where CourseID is not null)*100 as percentOfEnrollment
from Courses join Enrollments
using(CourseID)
where YEAR(EnrollmentDate)>=2023
group by Courses.CourseID,CourseName;

695c9ecbd574119fd5c0c11a.sql:
select CONCAT(FirstName," ",LastName) as fullName, CourseName
from Lecturers left join Courses
using (CourseID)
order by CONCAT(FirstName," ",LastName);

695c9ecbd574119fd5c0c11c.sql:
update Enrollments
set Grade=Grade+6
where Grade<70 and CourseID = (select CourseID from Courses where CourseName = "Calculus I");

select StudentID, CourseName, Grade as oldGrade, Grade as newGrade
from Enrollments join Courses
using (CourseID)
where not(Grade>=70 and Grade-6<70) and CourseName = "Calculus I"
union
select StudentID, CourseName, Grade-6 as oldGrade, Grade as newGrade
from Enrollments join Courses
using (CourseID)
where (Grade>=70 and Grade-6<70) and CourseName = "Calculus I";

695c9ecbd574119fd5c0c11e.sql:
select Students.StudentID,CONCAT(Students.FirstName," ",Students.LastName) as StudentName,Students.City,CourseName,CONCAT(Lecturers.FirstName," ",Lecturers.LastName) as LecturersName
from Students join Enrollments join Courses join Lecturers
on Students.StudentID = Enrollments.StudentID and Enrollments.CourseID = Courses.CourseID and Courses.CourseID = Lecturers.CourseID and Students.City = Lecturers.City;

695c9ecbd574119fd5c0c122.sql:
select top 3 * from (
select Courses.CourseID,CourseName,avg(Grade) as average, count(*) as NumOfStudent
from Courses join Enrollments
using(CourseID)
group by Courses.CourseID,CourseName
order by avg(Grade) desc
);

695c9ecad574119fd5c0c10a.sql:
select StudentID, concat(FirstName,' ',LastName) FullName, CourseID, EnrollmentDate
from Students join Enrollments using (StudentID)
where datediff('2026-01-13', EnrollmentDate) <= 77;

695c9ecad574119fd5c0c10c.sql:
select S.StudentID, FirstName, LastName, avg(Grade)
from Students S join Enrollments using (StudentID)
group by S.StudentID, FirstName, LastName
having avg(Grade) = (select max(M) from (select avg(Grade) as M from Enrollments group by StudentID) as A);

695c9ecad574119fd5c0c110.sql:
select Department
from Courses join Enrollments using (CourseID)
where Grade = (select max(Grade) from Enrollments);

695c9ecad574119fd5c0c114.sql:
select CourseID, CourseName, count(StudentID) as NumberOfStudents, (count(StudentID) * 100 / (select count(*) from Enrollments)) as EnrollmentPercentage
from Courses C left outer join Enrollments using (CourseID)
where year(EnrollmentDate) >= 2023
group by C.CourseID, CourseName;

695c9ecad574119fd5c0c116.sql:
select strcmp((select top 1 City from Lecturers order by Seniority desc),
(select top 1 City from Students S join Enrollments E using (StudentID) join Courses C using (CourseID)
where CourseName = 'Database' order by E.Grade asc)) as result;

695c9ecbd574119fd5c0c118.sql:
select E.StudentID, (Grade * 1.1) as NewGrade, Department
from Students join Enrollments E using (StudentID) join Courses using (CourseID)
where Department ='Computer Science' and CourseName ='Introduction to CS' and E.StudentID in (select StudentID from Enrollments join Courses using (CourseID) where CourseName = 'Calculus I')
order by NewGrade desc, Department asc;

695c9ecbd574119fd5c0c11a.sql:
select FirstName, LastName, CourseName
from Lecturers left outer join Courses using (CourseID)
order by FirstName asc;

695c9ecbd574119fd5c0c11c.sql:
update Enrollments
set Grade = Grade + 6
where Grade<70 and CourseID =(select CourseID from Courses where CourseName='Calculus I');

select StudentID, CourseName, (Grade-6) as OldGrade , Grade as NewGrade
from Enrollments join Courses using (CourseID)
where CourseName = 'Calculus I' and Grade<76;

695c9ecbd574119fd5c0c11e.sql:
select S.StudentID, concat(S.FirstName,' ',S.LastName) as stuName, S.City, CourseName, concat(L.FirstName,' ',L.LastName) lecname
from Students S join Enrollments E using (StudentID) join Courses C using (CourseID) join Lecturers L using (CourseID)
where S.City = L.City;

695c9ecbd574119fd5c0c120.sql:
select S.StudentID, FirstName, LastName, avg(Grade)
from Students S join Enrollments using (StudentID) join Courses using (CourseID)
where Department ='Computer Science'
group by S.StudentID, FirstName, LastName
having avg(Grade) > (select avg(Grade) from Enrollments join Courses using (CourseID) where Department ='Computer Science');

695c9ecbd574119fd5c0c122.sql:
select top 3 C.CourseID, C.CourseName, avg(Grade) as AvgGrade, count(StudentID) as StudentCount
from Enrollments join Courses C using (CourseID)
group by C.CourseID, C.CourseName
order by AvgGrade desc;

695c9ecad574119fd5c0c10a.sql:
select s.studentid,concat(s.firstname," ",s.lastname),e.courseid,e.enrollmentdate
from enrollments as e join students as s 
using(studentid)
where(e.enrollmentdate between "2025-10-28" and "2026-01-13");

695c9ecad574119fd5c0c10e.sql:
select c.coursename,l.firstname,l.lastname,l.seniority,c.credits
from courses as c join lecturers as l 
using(courseid)
where(c.department="מדעי המחשב" and l.seniority>=7)
order by c.credits asc;

695c9ecad574119fd5c0c110.sql:
select c.department
from courses as c join enrollments as e 
using(courseid)
where e.grade=(select max(e.grade)
from enrollments as e);

695c9ecad574119fd5c0c112.sql:
select c.department,count(distinct l.lecturerid)
from courses as c join lecturers as l 
using(courseid)
where(l.seniority>12)
group by c.department
having count( distinct l.lecturerid)>=3;

695c9ecad574119fd5c0c114.sql:
select c.courseid,c.coursename,count(e.studentid),
count(e.studentid)*100/(select count(distinct studentid)from enrollments  
from courses as c join enrolments as e
using(courseid)
where e.enrollmentdate>="2023-01-01"
group by c.courseid,c.coursename;

695c9ecad574119fd5c0c116.sql:
select strcmp(select s.city
from students as s join enrollments as e 
using(studentid)
join courses as c 
using(courseid)
where c.coursename="Database" 
and e.grade=(select min(e.grade)
from enrollments),
l.city
from  lecturers as l 
where l.seniority=((select (max(l.seniority))))
from lecturers);

695c9ecbd574119fd5c0c118.sql:
select s.studentid,c.department,1.1*e.grade as new_grade
from students as s join enrollentdate as e 
using(studentid)
join courses as c
using(courseid)
where c.department="מדעי המחשב" and c.coursename="calculus I"
order by new_grade desc,c.department asc;

695c9ecbd574119fd5c0c11a.sql:
select l.firstname,l.lastname,c.coursename
from lecturers as l left outer join courses as c
using(courseid)
order by l.firstname,l.lastname asc;

695c9ecbd574119fd5c0c11c.sql:
update enrollments
set grade=grade+6
where grade<70 and coursename=(select coursename
from courses
where coursename="Calculus I");

select s.studentid,c.coursename,e.grade-6,e.grade                                                 
from courses as c join enrollments as e 
using(courseid)
join students as s 
using(studentid)
where (c.coursename="Calculus I" and e.grade<76);

695c9ecbd574119fd5c0c11e.sql:
select s.studentid,s.firstname,s.lastname,s.city
,c.coursename,l.firstname,l.lastname
from students as s join enrollments as e 
using(studentid)
join courses c
using(courseid)
join lecturers as l
using(courseid)
where city=some(select city
from students 
where strcmp(s.city,l.city));

695c9ecbd574119fd5c0c122.sql:
select top 3 c.courseid,c.coursename,avg(e.grade),count(e.studentid)
from courses as c join enrollments as e 
using(courseid)
group by c.courseid,c.coursename
order by avg(e.grade) desc;

695c9ecad574119fd5c0c10a.sql:
select E.StudentID,concat(FirstName,' ',LastName)as FullName,CourseID,EnrollmentDate
from Students as S Join Enrollments as E using(StudentID)
where DATEDIFF('2026-01-13',EnrollmentDate) between 0 and 11*7;

695c9ecad574119fd5c0c10c.sql:
select S.StudentID,concat(FirstName,' ',LastName) as FullName,A.Avg_Grades
from Students as S join (select StudentID,avg(Grade) as Avg_Grades from Enrollments group by StudentID) as A on(S.StudentID=A.StudentID)
where A.Avg_Grades=(select max(A.Avg_Grades) from Enrollments as En join (select StudentID,avg(Grade) as Avg_Grades from Enrollments group by StudentID) as A on(En.StudentID=A.StudentID));

695c9ecad574119fd5c0c10e.sql:
select CourseName,concat(FirstName,' ',LastName) as LecturerName,Seniority,Credits
from Courses as C join Lecturers as L using(CourseID)
where Department='Computer Science' and Seniority>=7
order by Credits;

695c9ecad574119fd5c0c110.sql:
select Department
