select T1.CourseID, T1.CourseName, T1.AvgGrade, T1.NumOfStudents
from (
    select C.CourseID, C.CourseName, avg(E.Grade) as AvgGrade, count(*) as NumOfStudents
    from Courses C join Enrollments E
    on C.CourseID = E.CourseID
    group by C.CourseID, C.CourseName
) as T1
where (
    select count(*)
    from (
        select C2.CourseID, avg(E2.Grade) as AvgGrade
        from Courses C2 join Enrollments E2
        on C2.CourseID = E2.CourseID
        group by C2.CourseID
    ) as T2
    where T2.AvgGrade > T1.AvgGrade
) < 3
order by T1.AvgGrade DESC;

